import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Grid,
  TextField,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  Card,
  CardContent,
  Alert,
  LinearProgress,
  Autocomplete,
} from '@mui/material';
import {
  Search,
  Download,
  Print,
  Inventory,
  Refresh,
  Warning,
  CheckCircle,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { reportService } from '../../services/reportService';
import { itemService } from '../../services/itemService';
import { brandService } from '../../services/brandService';
import { groupService } from '../../services/groupService';

const StockReport = () => {
  const [filters, setFilters] = useState({
    startDate: new Date(new Date().setDate(1)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0],
  });
  const [selectedItems, setSelectedItems] = useState([]);
  const [selectedBrands, setSelectedBrands] = useState([]);
  const [selectedGroups, setSelectedGroups] = useState([]);
  const [items, setItems] = useState([]);
  const [brands, setBrands] = useState([]);
  const [groups, setGroups] = useState([]);
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [summary, setSummary] = useState(null);

  useEffect(() => {
    fetchMasterData();
  }, []);

  const fetchMasterData = async () => {
    try {
      const [itemsRes, brandsRes, groupsRes] = await Promise.all([
        itemService.getAll(0, 1000),
        brandService.getAll(0, 1000),
        groupService.getAll(0, 1000),
      ]);
      setItems(itemsRes.content || []);
      setBrands(brandsRes.content || []);
      setGroups(groupsRes.content || []);
    } catch (error) {
      console.error('Failed to fetch master data:', error);
    }
  };

  const fetchReport = async () => {
    if (!filters.startDate || !filters.endDate) {
      setError('Please select both start and end dates');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const requestData = {
        startDate: filters.startDate,
        endDate: filters.endDate,
        itemIds: selectedItems.length > 0 ? selectedItems.map(i => i.id) : null,
        brandIds: selectedBrands.length > 0 ? selectedBrands.map(b => b.id) : null,
        groupIds: selectedGroups.length > 0 ? selectedGroups.map(g => g.id) : null,
      };
      const response = await reportService.getStockReport(requestData);
      setData(response.content || []);
      setSummary(response.summary || null);
      toast.success('Stock report loaded successfully');
    } catch (error) {
      setError('Failed to load stock report');
      toast.error('Failed to load stock report');
    } finally {
      setLoading(false);
    }
  };

  const getStockStatus = (item) => {
    const closingStock = item.closingStock || 0;
    const minStock = item.minStockLevel || 0;
    const maxStock = item.maxStockLevel || 0;

    if (closingStock <= 0) {
      return { label: 'Out of Stock', color: 'error' };
    }
    if (closingStock <= minStock) {
      return { label: 'Critical Stock', color: 'error' };
    }
    if (closingStock <= minStock * 2) {
      return { label: 'Low Stock', color: 'warning' };
    }
    if (maxStock > 0 && closingStock >= maxStock) {
      return { label: 'Over Stock', color: 'info' };
    }
    return { label: 'In Stock', color: 'success' };
  };

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <Inventory sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">Stock Report</Typography>
          <Typography variant="body2" color="textSecondary">
            View stock with opening, purchases, sales, and closing
          </Typography>
        </Box>
      </Box>

      {error && <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>{error}</Alert>}

      <Paper sx={{ p: 3, borderRadius: 2, mb: 3 }}>
        <Grid container spacing={2}>
          <Grid item xs={12} md={3}>
            <TextField fullWidth label="Start Date" type="date" value={filters.startDate}
              onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
              InputLabelProps={{ shrink: true }} />
          </Grid>
          <Grid item xs={12} md={3}>
            <TextField fullWidth label="End Date" type="date" value={filters.endDate}
              onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
              InputLabelProps={{ shrink: true }} />
          </Grid>
          <Grid item xs={12} md={6}>
            <Autocomplete
              multiple options={items}
              getOptionLabel={(option) => `${option.code} - ${option.name}`}
              value={selectedItems}
              onChange={(event, newValue) => setSelectedItems(newValue)}
              renderInput={(params) => <TextField {...params} label="Items (Optional)" placeholder="Search items..." />}
            />
          </Grid>
          <Grid item xs={12} md={6}>
            <Autocomplete
              multiple options={brands}
              getOptionLabel={(option) => option.name}
              value={selectedBrands}
              onChange={(event, newValue) => setSelectedBrands(newValue)}
              renderInput={(params) => <TextField {...params} label="Brands (Optional)" placeholder="Search brands..." />}
            />
          </Grid>
          <Grid item xs={12} md={6}>
            <Autocomplete
              multiple options={groups}
              getOptionLabel={(option) => option.name}
              value={selectedGroups}
              onChange={(event, newValue) => setSelectedGroups(newValue)}
              renderInput={(params) => <TextField {...params} label="Groups (Optional)" placeholder="Search groups..." />}
            />
          </Grid>
          <Grid item xs={12} md={6}>
            <Box display="flex" gap={1} flexWrap="wrap">
              <Button variant="contained" startIcon={<Search />} onClick={fetchReport} disabled={loading}>
                {loading ? 'Loading...' : 'Generate'}
              </Button>
              <Button variant="outlined" startIcon={<Refresh />} onClick={fetchReport}>Refresh</Button>
              <Button variant="outlined" startIcon={<Download />}>Export</Button>
              <Button variant="outlined" startIcon={<Print />} onClick={() => window.print()}>Print</Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>

      {summary && (
        <Grid container spacing={3} mb={3}>
          <Grid item xs={12} md={3}>
            <Card><CardContent>
              <Typography variant="body2" color="textSecondary">Total Items</Typography>
              <Typography variant="h5">{summary.totalItems || 0}</Typography>
            </CardContent></Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card><CardContent>
              <Typography variant="body2" color="textSecondary">Total Stock Value</Typography>
              <Typography variant="h5" color="primary">₹{summary.totalStockValue?.toFixed(2) || '0.00'}</Typography>
            </CardContent></Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card><CardContent>
              <Typography variant="body2" color="textSecondary">Low Stock Items</Typography>
              <Typography variant="h5" color="warning">{summary.lowStockItems || 0}</Typography>
            </CardContent></Card>
          </Grid>
          <Grid item xs={12} md={3}>
            <Card><CardContent>
              <Typography variant="body2" color="textSecondary">Out of Stock</Typography>
              <Typography variant="h5" color="error">{summary.outOfStock || 0}</Typography>
            </CardContent></Card>
          </Grid>
        </Grid>
      )}

      {loading ? (
        <Box sx={{ width: '100%', py: 4 }}><LinearProgress /></Box>
      ) : data.length > 0 ? (
        <Paper sx={{ p: 2, borderRadius: 2 }}>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                  <TableCell>Code</TableCell><TableCell>Item Name</TableCell>
                  <TableCell>Brand</TableCell><TableCell>Group</TableCell>
                  <TableCell align="right">Opening Stock</TableCell>
                  <TableCell align="right">Purchases</TableCell>
                  <TableCell align="right">Sales</TableCell>
                  <TableCell align="right">Closing Stock</TableCell>
                  <TableCell>Status</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item, index) => {
                  const stockStatus = getStockStatus(item);
                  return (
                    <TableRow key={index} hover>
                      <TableCell><Typography variant="body2" fontWeight={500}>{item.itemCode}</Typography></TableCell>
                      <TableCell>{item.itemName}</TableCell>
                      <TableCell>{item.brandName || '-'}</TableCell>
                      <TableCell>{item.groupName || '-'}</TableCell>
                      <TableCell align="right">{item.openingStock || 0}</TableCell>
                      <TableCell align="right">{item.purchases || 0}</TableCell>
                      <TableCell align="right">{item.sales || 0}</TableCell>
                      <TableCell align="right">
                        <Typography fontWeight="bold" color="primary">{item.closingStock || 0}</Typography>
                      </TableCell>
                      <TableCell>
                        <Chip label={stockStatus.label} color={stockStatus.color} size="small"
                          icon={stockStatus.color === 'success' ? <CheckCircle /> : <Warning />} />
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </TableContainer>
        </Paper>
      ) : (
        <Paper sx={{ p: 4, textAlign: 'center', borderRadius: 2 }}>
          <Typography color="textSecondary">
            {filters.startDate && filters.endDate
              ? 'No stock data found for the selected period'
              : 'Select date range and generate report'}
          </Typography>
        </Paper>
      )}
    </Box>
  );
};

export default StockReport;
